powerpagecomponent.content:
{
  "displayorder": 4,
  "pagetemplateid": "fc18a914-844b-4d5a-8ab2-020e60610c58",
  "parentpageid": "cb403430-2fb9-4936-a45c-db75f161d8ba",
  "partialurl": "View-My-Registration",
  "isroot": false,
  "rootwebpageid": "6eb68f58-cd0c-992c-35fa-e8f01825510d",
  "title": "View My Registration",
  "summary": "<p>This is a sample landing page designed to be a starting point for your website</p>",
  "copy": "{% fetchxml userRegistration %}

<fetch version="1.0" output-format="xml-platform" mapping="logical" distinct="false">
<entity name="er_registration">
<attribute name="er_registrationid"/>
<attribute name="er_registrantname"/>
<attribute name="createdon"/>
<attribute name="statuscode"/>
<attribute name="statecode"/>
<attribute name="er_registrationstatus"/>
<attribute name="er_registrationdate"/>
<attribute name="overriddencreatedon"/>
<attribute name="owningbusinessunit"/>
<attribute name="ownerid"/>
<attribute name="modifiedon"/>
<attribute name="modifiedonbehalfby"/>
<attribute name="modifiedby"/>
<attribute name="er_event"/>
<attribute name="er_email"/>
<attribute name="createdonbehalfby"/>
<attribute name="createdby"/>
<attribute name="er_registeredby"/>

<order attribute="er_registrantname" descending="false"/>

<filter type ="and">
  <condition attribute="er_registeredby" operator="eq" value="{{user.id}}" />
</filter>

</entity>
</fetch>

{% endfetchxml %}

<div class="container mt-5">

  <!-- Header -->
  <div class="d-flex justify-content-between align-items-center mb-4">
    <h2>Registrations</h2>
    <a href="/registration/" class="btn btn-warning">
      New Registration
    </a>
  </div>

  <!-- Table -->
  <table class="table table-bordered table-hover">
    <thead class="thead-light">
      <tr>
        <th>Registrant Name</th>
        <th>Email</th>
        <th>Registration Status</th>
        <th style="width: 180px;">Actions</th>
      </tr>
    </thead>

    <tbody>
      {% if userRegistration.results.entities.size > 0 %}
        {% for result in userRegistration.results.entities %}
          <tr>
            <td>{{ result.er_registrantname }}</td>
            <td>{{ result.er_email }}</td>
            <td>{{ result.er_registrationstatus.label }}</td>
            <td>
         <a href="/edit-registration/?id={{result.er_registrationid}}" class="btn btn-sm btn-warning" title="Edit"><i class="fas fa-edit"></i></a> 
         <a id="{{result.er_registrationid}}" class="btn btn-sm btn-danger delete-btn" title="Delete"><i class="fas fa-trash-alt"></i></a> 
         <a href="/view-registration-detail/?id={{result.er_registrationid}}" class="btn btn-sm btn-info" title="View"><i class="fa fa-eye": </td>  




            </td>
          </tr>
        {% endfor %}
      {% else %}
        <tr>
          <td colspan="4" class="text-center">
            No registrations found
          </td>
        </tr>
      {% endif %}
    </tbody>
  </table>

</div>

<!-- Include Font Awesome for icons -->
<link rel="stylesheet"
href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/5.15.4/css/all.min.css">
{% include "WebAPI Wrapper" %}",
  "publishingstateid": "706c8d44-f8a7-4d37-803a-01690654b0df",
  "enablerating": false,
  "enabletracking": false,
  "excludefromsearch": false,
  "hiddenfromsitemap": true,
  "sharedpageconfiguration": false,
  "feedbackpolicy": 756150000,
  "customjavascript": "document.addEventListener('DOMContentLoaded', function () {

  document.querySelectorAll('.delete-btn').forEach(button => {

    button.addEventListener('click', function (event) {
      event.preventDefault();

      // ✅ Correctly get the record ID
      const registerid = this.id;

      if (!registerid) {
        alert("Record ID not found.");
        return;
      }

      // Confirm deletion
      if (confirm('Are you sure you want to delete this Registration?')) {

        webapi.safeAjax({
          type: "DELETE",
          url: "/_api/er_registrations(" + registerid + ")",
          contentType: "application/json",
          success: function () {
            alert("Deleted Record Successfully");
            location.reload();
          },
          error: function (xhr) {
            alert("Delete failed: " + xhr.responseText);
          }
        });

      }
    });

  });

});"
}
